formulas.formula:
=ARRAYFORMULA( IF(AC7:AC="","",
IF(I7:I="","",
IF(I7:I-TODAY()>60,
I7:I-30,
IF(I7:I-TODAY()>20,
TODAY()+7,
TODAY()
)))
)
)

=QUERY(
  {
    {
      Orders!B9:B,
      Orders!D9:D,
      ARRAYFORMULA(IF(Orders!B9:B<>"", J3, )),
      Orders!AB9:AD
    };
